private void tdCredit_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
        // --- Get values from the current row ---
    decimal eggsSetted = GetCurrentColumnValue("EggsSetted") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("EggsSetted"))
        : 0;

    decimal selChicks = GetCurrentColumnValue("SelChicks") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("SelChicks"))
        : 0;

    decimal culls = GetCurrentColumnValue("Culls") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("Culls"))
        : 0;

    decimal deadChicks = GetCurrentColumnValue("DeadChicks") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("DeadChicks"))
        : 0;

    // --- TotalChicks = SelChicks + Culls + DeadChicks ---
    decimal totalChicks = selChicks + culls + deadChicks;
    totalChicksSum += totalChicks ;
    // --- Calculate percentage ---
    decimal result = (eggsSetted > 0)
        ? (totalChicks * 100 / eggsSetted)
        : 0;

    // --- Assign to cell ---

    ((XRTableCell)sender).Text = result.ToString("0.00");

}

