private void xrTableCell28_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    //-- new logic for Cum Chicks Percentage minus StadCumHatchability
// --- Declare variables ---
decimal cumSettingEggs = 0;
decimal cumDeadChicks = 0;
decimal cumCulls = 0;
decimal cumBroiler = 0;
decimal stadCumHatchability = 0;
decimal resultValue = 0;

// --- Read values safely ---
if (GetCurrentColumnValue("CumSettingEggs") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("CumSettingEggs").ToString()))
{
    cumSettingEggs = Convert.ToDecimal(GetCurrentColumnValue("CumSettingEggs"));
}

if (GetCurrentColumnValue("CumDeadChicks") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("CumDeadChicks").ToString()))
{
    cumDeadChicks = Convert.ToDecimal(GetCurrentColumnValue("CumDeadChicks"));
}

if (GetCurrentColumnValue("CumCulls") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("CumCulls").ToString()))
{
    cumCulls = Convert.ToDecimal(GetCurrentColumnValue("CumCulls"));
}

if (GetCurrentColumnValue("CumBroiler") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("CumBroiler").ToString()))
{
    cumBroiler = Convert.ToDecimal(GetCurrentColumnValue("CumBroiler"));
}

if (GetCurrentColumnValue("StadCumHatchability") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("StadCumHatchability").ToString()))
{
    stadCumHatchability = Convert.ToDecimal(GetCurrentColumnValue("StadCumHatchability"));
}

// --- Calculate (CumDeadChicks + CumCulls + CumBroiler) * 100 / CumSettingEggs ---
decimal cumChicksPercent = 0;
if (cumSettingEggs > 0)
{
    cumChicksPercent = (cumDeadChicks + cumCulls + cumBroiler) * 100 / cumSettingEggs;
}

// --- Final result: subtract StadCumHatchability ---
resultValue = cumChicksPercent - stadCumHatchability;

// --- Optional: accumulate total ---
totalCumChicksMinusHatchabilityReport += resultValue;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = resultValue.ToString("N2");

}

