private void xrTableCell22_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    //-- new logic for Cum Broiler Percentage minus StadCumHatchabilityAGrade
// --- Declare variables ---
decimal cumSettingEggs = 0;
decimal cumBroiler = 0;
decimal stadCumHatchabilityAGrade = 0;
decimal resultValue = 0;

// --- Read values safely ---
if (GetCurrentColumnValue("CumSettingEggs") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("CumSettingEggs").ToString()))
{
    cumSettingEggs = Convert.ToDecimal(GetCurrentColumnValue("CumSettingEggs"));
}

if (GetCurrentColumnValue("CumBroiler") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("CumBroiler").ToString()))
{
    cumBroiler = Convert.ToDecimal(GetCurrentColumnValue("CumBroiler"));
}

if (GetCurrentColumnValue("StadCumHatchabilityAGrade") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("StadCumHatchabilityAGrade").ToString()))
{
    stadCumHatchabilityAGrade = Convert.ToDecimal(GetCurrentColumnValue("StadCumHatchabilityAGrade"));
}

// --- Equation (same as (Iif(CumSettingEggs > 0, CumBroiler / CumSettingEggs * 100, 0)) - StadCumHatchabilityAGrade) ---
decimal cumBroilerPercent = 0;

if (cumSettingEggs > 0)
{
    cumBroilerPercent = (cumBroiler / cumSettingEggs) * 100;
}

resultValue = cumBroilerPercent - stadCumHatchabilityAGrade;

// --- Optional: accumulate total ---
totalCumBroilerMinusHatchabilityAGradeReport += resultValue;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = resultValue.ToString("N2");

}



private void xrTableCell6_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     decimal eggsSetted;
    decimal culls;
    decimal deadChicks;
    decimal rejectChicks = 0;
    decimal result = 0;

    // Assignments
    eggsSetted = GetCurrentColumnValue("EggsSetted") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("EggsSetted"))
        : 0;

    culls = GetCurrentColumnValue("Culls") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("Culls"))
        : 0;

    deadChicks = GetCurrentColumnValue("DeadChicks") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("DeadChicks"))
        : 0;

    // --- Calculate percentage ---
    rejectChicks = culls + deadChicks;

    if (eggsSetted > 0)
    {
        result = (rejectChicks * 100m) / eggsSetted;
    }
         // --- Assign to cell ---
    ((XRTableCell)sender).Text = result.ToString("0.00");
    RejEggsSum += eggsSetted ;
    TotalCullsReport += culls ;
    TotalDeadChicksReport += deadChicks ;
    rejectChicksSum = TotalCullsReport  + TotalDeadChicksReport ;

}

private void xrTableCell55_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     // --- Use global variables directly ---
